"""Base plugin protocol using abstract inheritance."""
from abc import ABC, abstractmethod
from typing import Any, List


class PluginError(Exception):
    """Custom error type for plugin failures."""
    def __init__(self, plugin_name: str, original: Exception):
        self.plugin_name = plugin_name
        self.original = original
        super().__init__(f"[{plugin_name}] {original}")


class Plugin(ABC):
    """Abstract base class for all plugins.

    Subclasses must implement process(), validate(), and on_error().
    """

    name: str = "base"

    @abstractmethod
    def process(self, data: list) -> list:
        """Process input data and return transformed result."""
        ...

    @abstractmethod
    def validate(self, input_data: Any) -> bool:
        """Validate input before processing."""
        ...

    @abstractmethod
    def on_error(self, exc: Exception) -> str:
        """Handle an error during processing. Returns error description."""
        ...

