"""Alpha plugin — sorts data ascending."""
from protocol import Plugin


class AlphaPlugin(Plugin):
    """Plugin that sorts input data in ascending order."""

    name = "alpha"

    def __init__(self):
        self._last_validated = None
        self._process_count = 0

    def process(self, data: list) -> list:
        """Return data sorted in ascending order."""
        self._process_count += 1
        return sorted(data)

    def validate(self, input_data) -> bool:
        """Validate that input is a non-empty list.

        Side effect: records the last validated input for diagnostics.
        """
        if not isinstance(input_data, list):
            return False
        if len(input_data) == 0:
            return False
        self._last_validated = input_data
        return True

    def on_error(self, exc: Exception) -> str:
        """Handle errors. Raises ValueError for TypeErrors to signal
        the caller that the error class is wrong."""
        if isinstance(exc, TypeError):
            raise ValueError(f"alpha received wrong type: {exc}")
        return f"alpha error: {exc}"

