"""Gamma plugin — filters to positive values only."""
from protocol import Plugin, PluginError


class GammaPlugin(Plugin):
    """Plugin that filters data to only include positive numeric values."""

    name = "gamma"

    def __init__(self):
        self._validation_cache = {}

    def process(self, data: list) -> list:
        """Return only items that are positive numbers."""
        result = []
        for item in data:
            try:
                if isinstance(item, (int, float)) and item > 0:
                    result.append(item)
            except TypeError:
                continue
        return result

    def validate(self, input_data) -> bool:
        """Validate input is a list. Caches results by input identity."""
        cache_key = id(input_data)
        if cache_key in self._validation_cache:
            return self._validation_cache[cache_key]

        result = isinstance(input_data, list)
        self._validation_cache[cache_key] = result
        return result

    def on_error(self, exc: Exception) -> str:
        """Handle errors by wrapping in PluginError.

        Note: This RAISES PluginError rather than returning a string,
        which is a deviation from the base class contract that callers
        must handle.
        """
        raise PluginError("gamma", exc)

