"""Plugin registry — discovers, loads, and orchestrates plugins."""
from typing import List, Optional
from protocol import Plugin, PluginError


class PluginRegistry:
    """Manages plugin lifecycle and orchestration."""

    def __init__(self):
        self._plugins: List[Plugin] = []
        self._error_log: list = []

    def register(self, plugin: Plugin) -> None:
        """Register a plugin instance.

        Args:
            plugin: Must be an instance of Plugin.
        """
        if not isinstance(plugin, Plugin):
            raise TypeError(f"Expected Plugin instance, got {type(plugin).__name__}")
        self._plugins.append(plugin)

    def get_plugin(self, name: str) -> Optional[Plugin]:
        """Find a plugin by name."""
        for p in self._plugins:
            if p.name == name:
                return p
        return None

    def process_all(self, data: list) -> list:
        """Run all plugins' process() and merge results.

        Results are merged via list.extend() — each plugin MUST return a list.
        """
        merged = []
        for plugin in self._plugins:
            try:
                result = plugin.process(data)
                merged.extend(result)  # depends on result being a list
            except Exception as e:
                self._error_log.append((plugin.name, str(e)))
        return merged

    def validate_all(self, input_data) -> dict:
        """Run all plugins' validate() and collect results.

        Returns dict mapping plugin name to validation result.
        Also checks AlphaPlugin's _last_validated attribute for diagnostics.
        """
        results = {}
        for plugin in self._plugins:
            results[plugin.name] = plugin.validate(input_data)

        # Diagnostic: check that AlphaPlugin recorded the input
        alpha = self.get_plugin("alpha")
        if alpha is not None and hasattr(alpha, '_last_validated'):
            results['_alpha_diagnostic'] = alpha._last_validated

        return results

    def handle_errors(self, exc: Exception) -> list:
        """Dispatch error to all plugins and collect responses.

        Handles the special case where a plugin's on_error() raises
        instead of returning (e.g., GammaPlugin raises PluginError,
        AlphaPlugin raises ValueError for TypeErrors).
        """
        responses = []
        for plugin in self._plugins:
            try:
                msg = plugin.on_error(exc)
                responses.append((plugin.name, "handled", msg))
            except PluginError as pe:
                responses.append((plugin.name, "plugin_error", str(pe)))
            except ValueError as ve:
                responses.append((plugin.name, "value_error", str(ve)))
            except Exception as e:
                responses.append((plugin.name, "unexpected", str(e)))
        return responses

    @property
    def plugins(self) -> List[Plugin]:
        """Get registered plugins."""
        return list(self._plugins)

    @property
    def error_log(self) -> list:
        """Get error log."""
        return list(self._error_log)
